.sse-form-success, .sse-form-error {
    padding: 20px;
    border-radius: 8px;
    font-weight: 500;
    line-height: 1.5;
    box-shadow: 0 4px 15px rgba(0,0,0,0.1);
    margin-bottom: 25px !important;
    font-family: inherit;
    font-size: 1rem;
    text-align: center;
    display: block !important;
}
