    background-color: #d1fae5 !important; border: 1px solid #10b981 !important; color: #065f46 !important;
}
.sse-form-error {
    background-color: #fee2e2 !important; border: 1px solid #ef4444 !important; color: #991b1b !important;
}
.sse-spinner {
    display: inline-block; width: 1em; height: 1em; border-radius: 50%;
    border: 2px solid currentColor; border-right-color: transparent;
    animation: sse-spin 0.75s linear infinite; vertical-align: middle; margin-left: 0.5em; opacity: 0.7;
}
@keyframes sse-spin { to { transform: rotate(360deg); } }
.sse-form-success a, .sse-form-error a { color: inherit !important; text-decoration: underline; font-weight: 700; }

/* =========================================
   2. ЖЕСТКИЙ ЛЕЙАУТ (Всё в столбик)
   ========================================= */

/* Убиваем любые гриды и флексы внутри формы, чтобы блоки встали друг под другом */
form .srfm-layout-grid,
form .srfm-row,
form .srfm-col,
form .elementor-column,
form .sys-block-column,
form .sys-block-columns,
form > div {
    display: block !important;
    width: 100% !important;
    max-width: 100% !important;
    flex: none !important;
    float: none !important;
    margin-left: 0 !important;
    margin-right: 0 !important;
}

/* Отступы между полями */
.srfm-block-single, form p, form > div {
    margin-bottom: 20px !important;
    position: relative;
}

/* =========================================
   3. ПОЛЯ ВВОДА (Тёмная тема)
   ========================================= */
form input:not([type="submit"]):not([type="checkbox"]):not([type="radio"]),
form textarea,
form select {
    background-color: rgba(255, 255, 255, 0.07) !important;
    border: 1px solid rgba(128, 128, 128, 0.4) !important;
    color: inherit !important;
    
    display: block !important;
    width: 100% !important;
    max-width: 100% !important;
    padding: 12px 16px !important;
    border-radius: 4px !important;
    box-sizing: border-box !important;
    margin: 0 !important;
    outline: none;
    font-size: 16px !important;
    line-height: 1.5 !important;
    box-shadow: none !important;
    transition: all 0.2s ease;
}

/* Хак от белого фона автозаполнения */
form input:-webkit-autofill,
form input:-webkit-autofill:hover, 
form input:-webkit-autofill:focus, 
form textarea:-webkit-autofill {
    -webkit-transition: background-color 5000s ease-in-out 0s;
    transition: background-color 5000s ease-in-out 0s;
    -webkit-text-fill-color: inherit !important;
}

form input:focus, form textarea:focus {
    border-color: currentColor !important;
    background-color: rgba(255, 255, 255, 0.12) !important;
}

/* Красная рамка при ошибке */
form input.sse-is-invalid, form textarea.sse-is-invalid {
    border-color: #ff4d4d !important;
    background-color: rgba(255, 0, 0, 0.05) !important;
}

/* Лейблы */
form label {
    display: block !important;
    margin-bottom: 8px !important;
    font-weight: 600 !important;
    opacity: 0.95;
    color: inherit !important;
    font-size: 0.95em !important;
    line-height: 1.2 !important;
}

/* =========================================
   4. СООБЩЕНИЯ ОБ ОШИБКАХ (Красный текст)
   ========================================= */

/* Скрываем старые/битые сообщения темы */
form .srfm-error-message, form .error-message, form .wpcf7-not-valid-tip {
    display: none !important;
}

/* Наши новые, созданные JS сообщения */
.sse-js-error-message {
    color: #ff4d4d !important;
    font-size: 13px !important;
    margin-top: 6px !important;
    font-weight: normal !important;
    display: block !important;
    animation: sse-fade 0.3s ease;
    text-align: left !important;
}
@media (prefers-color-scheme: light) {
    .sse-js-error-message { color: #d32f2f !important; }
}
@keyframes sse-fade { from{opacity:0;transform:translateY(-3px)} to{opacity:1;transform:translateY(0)} }

/* Кнопка */
form button[type="submit"], form input[type="submit"] {
    cursor: pointer !important;
    margin-top: 10px !important;
}
form button[aria-busy="true"], form input[aria-busy="true"] {
    opacity: 0.6; cursor: wait !important; pointer-events: none;
}</style>
<script>(function(){
